INSERT INTO public.blog_posts (slug, title, excerpt, content, category, tags, reading_time, is_featured, is_published, published_at, meta_title, meta_description, author_name, faq_data) VALUES
('consolidacion-asesorias-espana-2026', 'La ola de consolidación de asesorías en España: quién está comprando y por qué [2026]', 'Al menos seis plataformas respaldadas por capital privado internacional compiten por adquirir asesorías en España.', '<p>El sector de asesorías en España está viviendo su mayor transformación en décadas. En los últimos 18 meses, al menos <strong>seis plataformas respaldadas por capital privado internacional</strong> han entrado a competir por adquirir despachos profesionales.</p><table><thead><tr><th>Plataforma</th><th>Inversor</th><th>Dato clave</th></tr></thead><tbody><tr><td>Afianza</td><td>BlackRock</td><td>110 M€</td></tr><tr><td>Auren</td><td>Waterland</td><td>Inversión estratégica</td></tr><tr><td>Grant Thornton</td><td>New Mountain Capital</td><td>Adquisición completa</td></tr><tr><td>Asenza</td><td>Ufenau Capital</td><td>Sagardoy + Carrillo</td></tr><tr><td>Adlanter</td><td>Artá Capital</td><td>Plan 30 adquisiciones</td></tr><tr><td>ETL Global</td><td>KKR</td><td>+140 oficinas</td></tr></tbody></table><p>España, con más de <strong>60.000 asesorías — el 93% con menos de 5 empleados</strong> — representa uno de los mercados más fragmentados de Europa.</p><h2>¿Por qué ahora? Tres fuerzas convergen</h2><h3>1. La demografía</h3><p>El <strong>45% de los titulares tiene entre 41 y 50 años</strong>. Entre 2021 y 2023 cerraron más de <strong>11.000 despachos</strong>, un 7% del total.</p><h3>2. La tecnología</h3><p>Facturación electrónica obligatoria, TicketBAI e IA fuerzan inversiones que una asesoría pequeña no puede asumir sola. El <strong>66% no dispone de plataformas telemáticas</strong>.</p><h3>3. El arbitraje de múltiplos</h3><p>Los fondos adquieren a <strong>3-5x EBITDA</strong> y construyen plataformas valoradas a <strong>8-12x</strong>. Citrin Cooperman pasó de 11x a 15x en tres años.</p><h2>¿Qué significa para el dueño de una asesoría?</h2><p>Por primera vez hay <strong>compradores serios con capital disponible</strong>. Pero la ventana tiene fecha de caducidad.</p><blockquote><p>Las plataformas que se construyan ahora serán las que capturen el valor de esta consolidación.</p></blockquote><p><strong><a href="/lp/calculadora-asesorias">→ Calcula el valor de tu asesoría con nuestra herramienta gratuita</a></strong></p>', 'M&A', ARRAY['consolidación','asesorías','private equity','España'], 8, true, true, now(), 'Consolidación de asesorías en España 2026: quién compra y por qué', 'BlackRock, Waterland, KKR y otros fondos compiten por asesorías españolas. Descubre quién compra y qué significa para tu despacho.', 'Samuel Navarro', '[{"question":"¿Quién está comprando asesorías en España en 2026?","answer":"Afianza (BlackRock), Auren (Waterland), Grant Thornton (New Mountain Capital), Asenza (Ufenau), Adlanter (Artá) y ETL Global (KKR)."},{"question":"¿Por qué los fondos compran asesorías?","answer":"Arbitraje de múltiplos: adquieren a 3-5x EBITDA y construyen plataformas valoradas a 8-12x."},{"question":"¿Cuántas asesorías han cerrado en España?","answer":"Más de 11.000 entre 2021 y 2023, un 7% del total."},{"question":"¿Es buen momento para vender?","answer":"Sí. Seis plataformas PE-backed compiten activamente, elevando precios."}]'::jsonb),

('cuanto-vale-asesoria-multiplos-2026', '¿Cuánto vale tu asesoría? Los múltiplos reales en 2026', 'Múltiplos sobre ingresos recurrentes, EBITDA y SDE: los rangos reales de valoración de asesorías en España.', '<p>Es la pregunta que más nos hacen. La respuesta corta: depende. Pero hoy hay más datos que nunca.</p><h2>Las tres métricas que determinan el precio</h2><h3>Múltiplo sobre ingresos recurrentes</h3><p>Rango habitual: <strong>0,7x a 1,5x</strong> los ingresos anuales recurrentes.</p><h3>Múltiplo sobre EBITDA</h3><p>En España: <strong>3-5x EBITDA</strong> entre particulares. Plataformas grandes: <strong>6-8x</strong>. PE-backed en UK/US: <strong>10-15x</strong>.</p><table><thead><tr><th>Tipo de operación</th><th>Múltiplo EBITDA</th></tr></thead><tbody><tr><td>Venta entre particulares</td><td>3-5x</td></tr><tr><td>Plataforma multi-oficina</td><td>6-8x</td></tr><tr><td>PE-backed (UK/US)</td><td>10-15x</td></tr></tbody></table><h3>Múltiplo sobre SDE</h3><p>Rangos en <strong>1,8-3,3x SDE</strong>.</p><h2>¿Qué sube y qué baja el precio?</h2><ul><li><strong>Retención de clientes</strong> superior al 92%</li><li><strong>Mix de servicios</strong> diversificado</li><li><strong>Baja dependencia del fundador</strong></li><li><strong>Cartera diversificada</strong> (top-10 &lt; 35%)</li><li><strong>Digitalización</strong> cloud-native</li></ul><h2>Lo que ha cambiado en 2025-2026</h2><p>Seis plataformas compitiendo han <strong>elevado precios</strong> y creado <strong>demanda constante</strong>.</p><blockquote><p>Si tu asesoría factura menos de 500.000€ con alta dependencia del fundador, el mercado ofrece menos opciones.</p></blockquote><p><strong><a href="/lp/calculadora-asesorias">→ Calcula el valor de tu asesoría</a></strong></p>', 'Valoración', ARRAY['valoración','múltiplos','EBITDA','asesorías'], 7, false, true, now(), '¿Cuánto vale tu asesoría? Múltiplos reales 2026', 'Múltiplos de 3-5x EBITDA, 0,7-1,5x ingresos: descubre cuánto vale tu asesoría en 2026.', 'Samuel Navarro', '[{"question":"¿Cuánto vale una asesoría en España en 2026?","answer":"Carteras a 0,7-1,5x ingresos recurrentes, asesorías estructuradas a 3-5x EBITDA, plataformas a 6-8x."},{"question":"¿Qué múltiplo de EBITDA se paga?","answer":"3-5x entre particulares, 6-8x plataformas, 10-15x PE-backed en UK/US."},{"question":"¿Qué factores aumentan el valor?","answer":"Retención >92%, mix diversificado, baja dependencia del fundador, digitalización."},{"question":"¿Qué es el SDE?","answer":"Seller''s Discretionary Earnings: suma salario del dueño al beneficio operativo. Se valora a 1,8-3,3x."}]'::jsonb),

('vender-asesoria-guia-maximizar-precio', 'Vender tu asesoría: guía para preparar la operación y maximizar el precio [2026]', 'La diferencia entre una venta bien ejecutada y una mal preparada puede suponer un 30-50% en el precio final.', '<p>No es un proceso que se improvise: <strong>la diferencia entre una venta bien y mal preparada puede suponer un 30-50% en el precio final</strong>.</p><h2>Paso 1: Entiende tu posición</h2><p>Necesitas una valoración realista, idealmente <strong>12-18 meses antes</strong>.</p><p><strong><a href="/lp/calculadora-asesorias">→ Valora tu asesoría con nuestra calculadora</a></strong></p><h2>Paso 2: Prepara la asesoría</h2><ul><li><strong>Contratos formales</strong> con clientes</li><li><strong>3 años de P&amp;L</strong> auditables</li><li><strong>Equipo estable</strong> y con contratos</li><li><strong>Tecnología cloud</strong> (A3, Sage, Holded)</li><li><strong>Cartera diversificada</strong> (top-10 &lt; 35%)</li></ul><h2>Paso 3: Elige la estructura</h2><h3>Venta total (100%)</h3><p><strong>60-80% al cierre + 20-40% earn-out</strong> vinculado a retención 12-24 meses.</p><h3>Venta parcial con permanencia</h3><p>Vendes 60-80%, te quedas 2-3 años. Opción al <strong>"segundo cheque"</strong>.</p><h3>Integración en red</h3><p>Operatividad local bajo marca del grupo. Compensación en efectivo, equity o combinación.</p><h2>Paso 4: Busca un asesor</h2><blockquote><p>Con seis plataformas compitiendo, tener 3-4 en la mesa puede marcar 1-2x EBITDA de diferencia.</p></blockquote><h2>Paso 5: Fiscalidad</h2><p>Exención por reinversión, empresa familiar, holding... cada caso es distinto.</p><h2>El momento es ahora</h2><p><strong><a href="/lp/calculadora-asesorias">→ Calcula el valor de tu asesoría</a></strong></p>', 'M&A', ARRAY['venta','asesorías','due diligence','preparación'], 9, false, true, now(), 'Vender tu asesoría: guía completa para maximizar el precio [2026]', 'Prepara la venta de tu asesoría en 5 pasos: valoración, due diligence, estructura, negociación y fiscalidad.', 'Samuel Navarro', '[{"question":"¿Cómo preparar mi asesoría para la venta?","answer":"Formaliza contratos, ten 3 años de cuentas auditables, estabiliza equipo, digitaliza y diversifica cartera."},{"question":"¿Cuánto tiempo necesito?","answer":"12-18 meses. Los que preparan obtienen 30-50% más."},{"question":"¿Qué es el earn-out?","answer":"Pago diferido (20-40%) vinculado a retención de clientes 12-24 meses."},{"question":"¿Necesito asesor de M&A?","answer":"Sí. Crea competencia entre compradores y puede marcar 1-2x EBITDA de diferencia."}]'::jsonb),

('crecer-comprando-plataforma-asesorias', 'Crecer comprando: cómo construir una plataforma de asesorías en España [2026]', 'El buy-and-build en servicios profesionales es una de las estrategias más probadas en private equity.', '<p>La consolidación del sector te ofrece una oportunidad que no existía hace cinco años.</p><h2>El modelo buy-and-build</h2><p>Adquieres bolt-ons a <strong>3-5x EBITDA</strong>, integras, y creas una plataforma valorada a <strong>8-12x EBITDA</strong>.</p><table><thead><tr><th>Plataforma</th><th>Modelo</th><th>Estado</th></tr></thead><tbody><tr><td>Afianza</td><td>Integración total</td><td>59 integraciones, €50M, €110M BlackRock</td></tr><tr><td>Adlanter</td><td>Holding</td><td>Plan 30 adquisiciones hasta €100M</td></tr><tr><td>Asenza</td><td>Holding federado</td><td>Sagardoy + Carrillo (Ufenau)</td></tr><tr><td>ETL Global</td><td>Red federada</td><td>+140 oficinas (KKR)</td></tr></tbody></table><h2>Tres modelos de consolidación</h2><h3>Integración total (Afianza)</h3><p>Marca única, máximas sinergias.</p><h3>Red federada (ETL Global)</h3><p>Autonomía local con servicios centrales compartidos.</p><h3>Plataforma holding (Asenza)</h3><p>Firmas autónomas con capital compartido.</p><h2>Lo que necesitas</h2><ol><li><strong>Escala mínima:</strong> €3-5M facturación</li><li><strong>Capital:</strong> 50-60% deuda + 40-50% equity</li><li><strong>Tesis de inversión clara</strong></li><li><strong>Equipo de integración</strong></li></ol><blockquote><p>El mayor riesgo no es comprar mal — es integrar mal.</p></blockquote><h2>El papel del asesor de M&amp;A</h2><p>Acceso a deal flow, valoración objetiva, estructuración y due diligence.</p><p><strong><a href="/lp/calculadora-asesorias">→ Accede a la calculadora de valoración</a></strong></p><p><em>Capittal Transacciones — M&amp;A · Consulting<br/>samuel@capittal.es | www.capittal.es</em></p>', 'M&A', ARRAY['buy-and-build','plataforma','adquisiciones','asesorías'], 8, false, true, now(), 'Buy-and-build de asesorías: cómo construir una plataforma en España [2026]', 'Guía para construir una plataforma de asesorías: modelos, financiación, escala mínima y claves de integración.', 'Samuel Navarro', '[{"question":"¿Qué es el buy-and-build?","answer":"Adquirir bolt-ons a 3-5x EBITDA e integrarlos en una plataforma valorada a 8-12x."},{"question":"¿Cuánta facturación necesito?","answer":"Al menos €3-5M y un equipo que funcione sin el fundador."},{"question":"¿Qué modelos de consolidación existen?","answer":"Integración total (Afianza), red federada (ETL Global) y holding (Asenza)."},{"question":"¿Cómo se financia?","answer":"50-60% deuda + 40-50% equity. CaixaBank, BlackRock, Artá y Ufenau son financiadores activos."}]'::jsonb);

ALTER TABLE public.blog_posts ENABLE TRIGGER trigger_google_indexing;